//! Qwen2.5-VL / Qwen2-VL Vision Transformer encoder.
//!
//! Faithful CPU/f32 port of the Qwen2.5-VL vision tower. Unlike the SigLIP-style
//! `model_molmoact2_vit.rs` (which this file mirrors in code STYLE only), the
//! Qwen2.5-VL ViT has a distinct architecture:
//!   - Conv3d patch embed (temporal_patch_size=2, patch=14) → hidden 1280
//!   - 2D rotary position embedding on (row, col) patch coordinates
//!   - Window attention on most blocks, FULL attention on the periodic blocks
//!     in `fullatt_block_indexes` ([7, 15, 23, 31] for the 3B)
//!   - RMSNorm (NOT LayerNorm), SwiGLU gated MLP (SiLU)
//!   - patch merger: RMSNorm → 2×2 spatial merge (1280·4=5120) → fc1 → GELU →
//!     fc2 → out_hidden 2048 (== text hidden)
//!
//! Output: `[n_merged_tokens, out_hidden]` f32, ready to splice into the text
//! residual stream in place of the `<|image_pad|>` tokens.
//!
//! Verified against Qwen/Qwen2.5-VL-3B-Instruct safetensors header (2026-05-24).
//!
//! Weight naming (written by encode-knot.py; KnotWriter joins `.`→`_`):
//!   vit_patch_embed_weight       [hidden=1280, patch_dim=in_chans*temporal*p*p]
//!   vit_blk_{i}_norm1_weight     [hidden]                RMSNorm (no bias)
//!   vit_blk_{i}_norm2_weight     [hidden]                RMSNorm (no bias)
//!   vit_blk_{i}_attn_qkv_weight  [3*hidden, hidden]      fused QKV
//!   vit_blk_{i}_attn_qkv_bias    [3*hidden]
//!   vit_blk_{i}_attn_proj_weight [hidden, hidden]
//!   vit_blk_{i}_attn_proj_bias   [hidden]
//!   vit_blk_{i}_mlp_gate_weight  [inter, hidden] + bias [inter]
//!   vit_blk_{i}_mlp_up_weight    [inter, hidden] + bias [inter]
//!   vit_blk_{i}_mlp_down_weight  [hidden, inter] + bias [hidden]
//!   vit_merger_ln_q_weight       [hidden]                RMSNorm
//!   vit_merger_fc1_weight        [merge_hidden, merge_hidden]  (merge_hidden = hidden*merge^2)
//!   vit_merger_fc1_bias          [merge_hidden]
//!   vit_merger_fc2_weight        [out_hidden, merge_hidden]
//!   vit_merger_fc2_bias          [out_hidden]

use std::sync::Arc;

use crate::loader::{KnotConfig, WeightBackend};
use crate::math::{accumulate_weighted, dot_product, gelu_inplace, mat_vec_f32, rms_norm, softmax};

// ─────────────────────────────────────────────────────────────────────────────
// Config (sourced from the knot's vit_* config fields; falls back to 3B values)
// ─────────────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone)]
pub struct Qwen2VlVitConfig {
    pub depth: usize,
    pub hidden_size: usize,
    pub num_heads: usize,
    pub intermediate_size: usize,
    pub patch_size: usize,
    pub temporal_patch_size: usize,
    pub in_chans: usize,
    pub spatial_merge_size: usize,
    pub window_size: usize,
    pub out_hidden_size: usize,
    pub fullatt_block_indexes: Vec<usize>,
    pub rms_norm_eps: f32,
}

impl Default for Qwen2VlVitConfig {
    fn default() -> Self {
        // Qwen2.5-VL-3B-Instruct vision_config (verified 2026-05-24).
        Self {
            depth: 32,
            hidden_size: 1280,
            num_heads: 16,
            intermediate_size: 3420,
            patch_size: 14,
            temporal_patch_size: 2,
            in_chans: 3,
            spatial_merge_size: 2,
            window_size: 112,
            out_hidden_size: 2048,
            fullatt_block_indexes: vec![7, 15, 23, 31],
            rms_norm_eps: 1e-6,
        }
    }
}

impl Qwen2VlVitConfig {
    /// Build a config from the knot metadata. The encoder writes vit_* fields
    /// onto the same KnotConfig block as the text dims. `KnotConfig` does not
    /// (yet) carry the vit_* fields as typed members, so we pull defaults here;
    /// callers may override after construction if they parse the raw JSON.
    pub fn from_knot_config(cfg: &KnotConfig) -> Self {
        // The vit_* tower geometry (depth/hidden/heads/patch/window) is shared by
        // every Qwen2.5-VL size — only the merger's OUTPUT width differs, and by
        // construction it equals the text hidden dim (the merger fc2 projects the
        // visual tokens straight into the LLM residual stream). So we keep the
        // shared ViT defaults but bind `out_hidden_size` to the knot's text
        // `hidden_dim`: 2048 for the 3B, 3584 for the 7B. This is exactly the
        // axis the splice check enforces (`out_hidden_size == hidden_dim`), and
        // it matches the stored fc2 weight shape [hidden_dim, merge_hidden].
        Self {
            out_hidden_size: cfg.hidden_dim,
            ..Self::default()
        }
    }

    #[inline]
    pub fn head_dim(&self) -> usize {
        self.hidden_size / self.num_heads
    }

    /// Flattened input dim of one Conv3d patch: in_chans * temporal * p * p.
    #[inline]
    pub fn patch_dim(&self) -> usize {
        self.in_chans * self.temporal_patch_size * self.patch_size * self.patch_size
    }

    #[inline]
    pub fn merge_unit(&self) -> usize {
        self.spatial_merge_size * self.spatial_merge_size
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-block tensor names (encoder writes `.`→`_` joined keys)
// ─────────────────────────────────────────────────────────────────────────────

struct VitBlockNames {
    norm1: String,
    norm2: String,
    qkv_w: String,
    qkv_b: String,
    proj_w: String,
    proj_b: String,
    gate_w: String,
    gate_b: String,
    up_w: String,
    up_b: String,
    down_w: String,
    down_b: String,
}

impl VitBlockNames {
    fn new(i: usize) -> Self {
        Self {
            norm1: format!("vit_blk_{i}_norm1_weight"),
            norm2: format!("vit_blk_{i}_norm2_weight"),
            qkv_w: format!("vit_blk_{i}_attn_qkv_weight"),
            qkv_b: format!("vit_blk_{i}_attn_qkv_bias"),
            proj_w: format!("vit_blk_{i}_attn_proj_weight"),
            proj_b: format!("vit_blk_{i}_attn_proj_bias"),
            gate_w: format!("vit_blk_{i}_mlp_gate_weight"),
            gate_b: format!("vit_blk_{i}_mlp_gate_bias"),
            up_w: format!("vit_blk_{i}_mlp_up_weight"),
            up_b: format!("vit_blk_{i}_mlp_up_bias"),
            down_w: format!("vit_blk_{i}_mlp_down_weight"),
            down_b: format!("vit_blk_{i}_mlp_down_bias"),
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// ViT
// ─────────────────────────────────────────────────────────────────────────────

pub struct Qwen2VlViT {
    pub config: Qwen2VlVitConfig,
    backend: Arc<dyn WeightBackend>,
    blocks: Vec<VitBlockNames>,
}

impl Qwen2VlViT {
    pub fn new(config: Qwen2VlVitConfig, backend: Arc<dyn WeightBackend>) -> Self {
        let blocks = (0..config.depth).map(VitBlockNames::new).collect();
        Self {
            config,
            backend,
            blocks,
        }
    }

    /// Encode a preprocessed image.
    ///
    /// `pixels` is the flattened patch grid in Qwen2.5-VL layout:
    ///   shape [n_patches, patch_dim]  (row-major, raster patch order)
    /// where patch_dim = in_chans * temporal_patch_size * patch * patch and
    /// each patch already carries the temporal duplication (frame copied twice).
    ///
    /// `grid_h`, `grid_w` are the patch-grid dimensions (grid_h*grid_w == n_patches).
    /// Both MUST be multiples of `spatial_merge_size`.
    ///
    /// Returns `[n_merged_tokens, out_hidden]` where
    ///   n_merged_tokens = n_patches / (spatial_merge_size^2)
    ///   out_hidden      = config.out_hidden_size (== text hidden, 2048).
    pub fn forward(
        &self,
        pixels: &[f32],
        grid_h: usize,
        grid_w: usize,
    ) -> Result<Vec<f32>, String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let n = grid_h * grid_w;
        let patch_dim = cfg.patch_dim();
        if pixels.len() != n * patch_dim {
            return Err(format!(
                "Qwen2VlViT::forward: pixels len {} != n_patches*patch_dim {}*{}={}",
                pixels.len(),
                n,
                patch_dim,
                n * patch_dim
            ));
        }
        if !grid_h.is_multiple_of(cfg.spatial_merge_size) || !grid_w.is_multiple_of(cfg.spatial_merge_size) {
            return Err(format!(
                "Qwen2VlViT::forward: grid {grid_h}x{grid_w} not divisible by merge {}",
                cfg.spatial_merge_size
            ));
        }

        // 1. Patch embed: project each patch [patch_dim] → [hidden] (Conv3d as matmul).
        let mut x = vec![0.0f32; n * h];
        {
            // qtype-aware (patch_embed is Q8_0-quantized by the encoder).
            let wf = self.fetch_f32("vit_patch_embed_weight")?;
            // weight is [hidden, patch_dim]; mat_vec_f32(out, in[patch_dim], w, patch_dim, hidden).
            for t in 0..n {
                let inp = &pixels[t * patch_dim..(t + 1) * patch_dim];
                let dst = &mut x[t * h..(t + 1) * h];
                mat_vec_f32(dst, inp, &wf, h, patch_dim);
            }
        }

        // 2. Precompute 2D-RoPE cos/sin tables per patch position.
        //    Qwen2.5-VL rotates each head's first half by row-freq and second
        //    half by col-freq. head_dim is split into two equal halves; within
        //    each half, the standard interleaved/half-rotation is applied.
        let head_dim = cfg.head_dim();
        let (cos_tab, sin_tab) = self.build_rope_tables(grid_h, grid_w, head_dim);

        // 3. Window assignment: which window each patch belongs to. Patches are
        //    grouped into spatial windows of `window_size` PIXELS == window_size /
        //    patch_size patches per side, further aligned to the spatial-merge
        //    grid. Full-attention blocks ignore windowing.
        let win_patches = (cfg.window_size / cfg.patch_size).max(1); // patches per window side
        let windows = self.assign_windows(grid_h, grid_w, win_patches);

        // 4. Transformer blocks.
        for l in 0..cfg.depth {
            let full_attn = cfg.fullatt_block_indexes.contains(&l);
            self.block(&mut x, l, n, &cos_tab, &sin_tab, &windows, full_attn)?;
        }

        // 5. Patch merger → [n_merged, out_hidden].
        self.merger(&x, grid_h, grid_w)
    }

    /// Build per-position cos/sin tables for 2D RoPE.
    /// Returns (cos, sin) each shaped [n_patches, head_dim].
    fn build_rope_tables(
        &self,
        grid_h: usize,
        grid_w: usize,
        head_dim: usize,
    ) -> (Vec<f32>, Vec<f32>) {
        let n = grid_h * grid_w;
        let half = head_dim / 2; // rows use [0,half), cols use [half,head_dim)
                                 // Each of the two halves has `half/2` frequency pairs (rotate pairs i, i+quarter).
        let quarter = half / 2;
        let theta = 10000.0f32;
        let mut cos = vec![0.0f32; n * head_dim];
        let mut sin = vec![0.0f32; n * head_dim];
        // inv_freq for `quarter` dims: theta^(-2i/half) is the Qwen ViT convention
        // (rotary dim per spatial axis = head_dim/2, so freqs span `quarter` values).
        let mut inv_freq = vec![0.0f32; quarter];
        for i in 0..quarter {
            inv_freq[i] = 1.0 / theta.powf((2 * i) as f32 / half as f32);
        }
        for r in 0..grid_h {
            for c in 0..grid_w {
                let p = r * grid_w + c;
                let base = p * head_dim;
                // Row half: dims [0, half)
                for i in 0..quarter {
                    let ang = r as f32 * inv_freq[i];
                    let (s, co) = ang.sin_cos();
                    cos[base + i] = co;
                    cos[base + i + quarter] = co;
                    sin[base + i] = s;
                    sin[base + i + quarter] = s;
                }
                // Col half: dims [half, head_dim)
                for i in 0..quarter {
                    let ang = c as f32 * inv_freq[i];
                    let (s, co) = ang.sin_cos();
                    cos[base + half + i] = co;
                    cos[base + half + i + quarter] = co;
                    sin[base + half + i] = s;
                    sin[base + half + i + quarter] = s;
                }
            }
        }
        (cos, sin)
    }

    /// Assign each patch to a window id. Windows tile the patch grid in blocks of
    /// `win_patches` × `win_patches`. Returns a Vec of window-id per patch (len n).
    fn assign_windows(&self, grid_h: usize, grid_w: usize, win_patches: usize) -> Vec<usize> {
        let n = grid_h * grid_w;
        let mut w = vec![0usize; n];
        let wcols = grid_w.div_ceil(win_patches);
        for r in 0..grid_h {
            for c in 0..grid_w {
                let wr = r / win_patches;
                let wc = c / win_patches;
                w[r * grid_w + c] = wr * wcols + wc;
            }
        }
        w
    }

    /// One transformer block: x += attn(rmsnorm1(x)); x += mlp(rmsnorm2(x)).
    #[allow(clippy::too_many_arguments)]
    fn block(
        &self,
        x: &mut [f32],
        l: usize,
        n: usize,
        cos_tab: &[f32],
        sin_tab: &[f32],
        windows: &[usize],
        full_attn: bool,
    ) -> Result<(), String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let inter = cfg.intermediate_size;
        let eps = cfg.rms_norm_eps;
        let bn = &self.blocks[l];

        // ── Attention ──
        // norm1
        let norm1 = self.fetch_f32(&bn.norm1)?;
        let mut xn = vec![0.0f32; n * h];
        for t in 0..n {
            rms_norm(
                &mut xn[t * h..(t + 1) * h],
                &x[t * h..(t + 1) * h],
                &norm1,
                eps,
            );
        }

        // qkv
        let qkv_w = self.fetch_f32(&bn.qkv_w)?;
        let qkv_b = self.fetch_f32(&bn.qkv_b)?;
        let n_heads = cfg.num_heads;
        let head_dim = cfg.head_dim();
        let qkv_dim = 3 * h;
        let mut q = vec![0.0f32; n * h];
        let mut k = vec![0.0f32; n * h];
        let mut v = vec![0.0f32; n * h];
        {
            let mut tmp = vec![0.0f32; qkv_dim];
            for t in 0..n {
                let inp = &xn[t * h..(t + 1) * h];
                mat_vec_f32(&mut tmp, inp, &qkv_w, qkv_dim, h);
                for i in 0..qkv_dim {
                    tmp[i] += qkv_b[i];
                }
                q[t * h..(t + 1) * h].copy_from_slice(&tmp[0..h]);
                k[t * h..(t + 1) * h].copy_from_slice(&tmp[h..2 * h]);
                v[t * h..(t + 1) * h].copy_from_slice(&tmp[2 * h..3 * h]);
            }
        }

        // apply 2D RoPE to q, k (per head)
        apply_rope(&mut q, cos_tab, sin_tab, n, n_heads, head_dim);
        apply_rope(&mut k, cos_tab, sin_tab, n, n_heads, head_dim);

        // attention (full or windowed), output into attn_out
        let scale = 1.0 / (head_dim as f32).sqrt();
        let mut attn_out = vec![0.0f32; n * h];
        if full_attn {
            self.attend_set(
                &q,
                &k,
                &v,
                &mut attn_out,
                &(0..n).collect::<Vec<_>>(),
                n_heads,
                head_dim,
                h,
                scale,
            );
        } else {
            // Group patches by window id, attend within each window only.
            let max_w = windows.iter().copied().max().map(|m| m + 1).unwrap_or(1);
            for wid in 0..max_w {
                let members: Vec<usize> = (0..n).filter(|&t| windows[t] == wid).collect();
                if members.is_empty() {
                    continue;
                }
                self.attend_set(
                    &q,
                    &k,
                    &v,
                    &mut attn_out,
                    &members,
                    n_heads,
                    head_dim,
                    h,
                    scale,
                );
            }
        }

        // output proj + residual add
        let proj_w = self.fetch_f32(&bn.proj_w)?;
        let proj_b = self.fetch_f32(&bn.proj_b)?;
        {
            let mut o = vec![0.0f32; h];
            for t in 0..n {
                mat_vec_f32(&mut o, &attn_out[t * h..(t + 1) * h], &proj_w, h, h);
                for i in 0..h {
                    x[t * h + i] += o[i] + proj_b[i];
                }
            }
        }

        // ── SwiGLU MLP ──
        let norm2 = self.fetch_f32(&bn.norm2)?;
        let gate_w = self.fetch_f32(&bn.gate_w)?;
        let gate_b = self.fetch_f32(&bn.gate_b)?;
        let up_w = self.fetch_f32(&bn.up_w)?;
        let up_b = self.fetch_f32(&bn.up_b)?;
        let down_w = self.fetch_f32(&bn.down_w)?;
        let down_b = self.fetch_f32(&bn.down_b)?;
        {
            let mut xn2 = vec![0.0f32; h];
            let mut gate = vec![0.0f32; inter];
            let mut up = vec![0.0f32; inter];
            let mut down = vec![0.0f32; h];
            for t in 0..n {
                rms_norm(&mut xn2, &x[t * h..(t + 1) * h], &norm2, eps);
                mat_vec_f32(&mut gate, &xn2, &gate_w, inter, h);
                mat_vec_f32(&mut up, &xn2, &up_w, inter, h);
                for i in 0..inter {
                    let g = gate[i] + gate_b[i];
                    let u = up[i] + up_b[i];
                    // SiLU(g) * u
                    gate[i] = (g / (1.0 + (-g).exp())) * u;
                }
                mat_vec_f32(&mut down, &gate, &down_w, h, inter);
                for i in 0..h {
                    x[t * h + i] += down[i] + down_b[i];
                }
            }
        }

        Ok(())
    }

    /// Multi-head attention over a SUBSET of token indices `members` (the window
    /// or the whole sequence for full-attention blocks). Writes into `attn_out`
    /// at each member's row.
    #[allow(clippy::too_many_arguments)]
    fn attend_set(
        &self,
        q: &[f32],
        k: &[f32],
        v: &[f32],
        attn_out: &mut [f32],
        members: &[usize],
        n_heads: usize,
        head_dim: usize,
        h: usize,
        scale: f32,
    ) {
        let m = members.len();
        let mut scores = vec![0.0f32; m];
        for &t_out in members {
            for head in 0..n_heads {
                let q_off = t_out * h + head * head_dim;
                let q_head = &q[q_off..q_off + head_dim];
                for (si, &t_src) in members.iter().enumerate() {
                    let k_off = t_src * h + head * head_dim;
                    scores[si] = dot_product(q_head, &k[k_off..k_off + head_dim]) * scale;
                }
                softmax(&mut scores[..m]);
                let out_off = t_out * h + head * head_dim;
                let head_out = &mut attn_out[out_off..out_off + head_dim];
                head_out.fill(0.0);
                for (si, &t_src) in members.iter().enumerate() {
                    let v_off = t_src * h + head * head_dim;
                    accumulate_weighted(head_out, &v[v_off..v_off + head_dim], scores[si]);
                }
            }
        }
    }

    /// Patch merger: RMSNorm(ln_q) → 2×2 spatial merge → fc1 → GELU → fc2.
    /// Returns [n_merged, out_hidden].
    fn merger(&self, x: &[f32], grid_h: usize, grid_w: usize) -> Result<Vec<f32>, String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let ms = cfg.spatial_merge_size;
        let merge_hidden = h * cfg.merge_unit();
        let out_hidden = cfg.out_hidden_size;
        let eps = cfg.rms_norm_eps;

        let ln_q = self.fetch_f32("vit_merger_ln_q_weight")?;
        let fc1_w = self.fetch_f32("vit_merger_fc1_weight")?;
        let fc1_b = self.fetch_f32("vit_merger_fc1_bias")?;
        let fc2_w = self.fetch_f32("vit_merger_fc2_weight")?;
        let fc2_b = self.fetch_f32("vit_merger_fc2_bias")?;

        // RMSNorm every patch first.
        let n = grid_h * grid_w;
        let mut xn = vec![0.0f32; n * h];
        for t in 0..n {
            rms_norm(
                &mut xn[t * h..(t + 1) * h],
                &x[t * h..(t + 1) * h],
                &ln_q,
                eps,
            );
        }

        let mh = grid_h / ms;
        let mw = grid_w / ms;
        let n_merged = mh * mw;
        let mut out = vec![0.0f32; n_merged * out_hidden];

        let mut merged = vec![0.0f32; merge_hidden];
        let mut fc1 = vec![0.0f32; merge_hidden];
        for br in 0..mh {
            for bc in 0..mw {
                // Concatenate the 2×2 block in (row-major within block) order.
                let mut off = 0;
                for dr in 0..ms {
                    for dc in 0..ms {
                        let r = br * ms + dr;
                        let c = bc * ms + dc;
                        let p = r * grid_w + c;
                        merged[off..off + h].copy_from_slice(&xn[p * h..(p + 1) * h]);
                        off += h;
                    }
                }
                // fc1 (merge_hidden → merge_hidden) + bias, GELU
                mat_vec_f32(&mut fc1, &merged, &fc1_w, merge_hidden, merge_hidden);
                for i in 0..merge_hidden {
                    fc1[i] += fc1_b[i];
                }
                gelu_inplace(&mut fc1);
                // fc2 (merge_hidden → out_hidden) + bias
                let mi = br * mw + bc;
                let dst = &mut out[mi * out_hidden..(mi + 1) * out_hidden];
                mat_vec_f32(dst, &fc1, &fc2_w, out_hidden, merge_hidden);
                for i in 0..out_hidden {
                    dst[i] += fc2_b[i];
                }
            }
        }
        Ok(out)
    }

    /// Fetch a vit tensor as f32, dequantizing per its declared qtype. The
    /// encoder Q8_0-quantizes large vit matrices (>=64K elems via `add_auto`)
    /// and keeps small ones (biases/norms) f32 — so a raw f32 reinterpret is
    /// wrong for the quantized matrices. `tensor_info` (MmapBackend/HttpBackend)
    /// reports the source qtype; F32 and Q8_0 (34-byte GGUF blocks) are the only
    /// two the encoder emits for these tensors.
    fn fetch_f32(&self, name: &str) -> Result<Vec<f32>, String> {
        let bytes = self
            .backend
            .fetch_tensor(name)
            .map_err(|e| format!("{name}: {e}"))?;
        let qtype = self
            .backend
            .tensor_info(name)
            .map(|ti| ti.tensor_type.to_ascii_lowercase())
            .unwrap_or_else(|| "f32".to_string());
        match qtype.as_str() {
            "q8_0" => {
                // GGUF Q8_0: 34-byte blocks (2-byte fp16 scale + 32 i8).
                let n_elems = (bytes.len() / 34) * 32;
                let mut out = vec![0f32; n_elems];
                crate::math::dequantize_q8_0_row(&mut out, &bytes, 0, n_elems);
                Ok(out)
            }
            "f32" | "fp32" => Ok(bytes_to_f32(&bytes).to_vec()),
            other => Err(format!(
                "fetch_f32 {name}: unsupported vit qtype '{other}' (expected f32 or Q8_0)"
            )),
        }
    }
}

/// Apply 2D RoPE in-place to a [n, n_heads*head_dim] buffer. cos/sin are
/// [n, head_dim] and shared across heads. Rotation is the half-split form:
///   out[i]        = x[i]*cos[i]      - x[i+hd/2]*sin[i]
///   out[i+hd/2]   = x[i+hd/2]*cos[i+hd/2] + x[i]*sin[i+hd/2]
/// matching Qwen2.5-VL's `apply_rotary_pos_emb_vision` (rotate_half).
fn apply_rope(
    buf: &mut [f32],
    cos: &[f32],
    sin: &[f32],
    n: usize,
    n_heads: usize,
    head_dim: usize,
) {
    let h = n_heads * head_dim;
    let half = head_dim / 2;
    for t in 0..n {
        let cbase = t * head_dim;
        for head in 0..n_heads {
            let base = t * h + head * head_dim;
            for i in 0..half {
                let x0 = buf[base + i];
                let x1 = buf[base + i + half];
                let c0 = cos[cbase + i];
                let s0 = sin[cbase + i];
                let c1 = cos[cbase + i + half];
                let s1 = sin[cbase + i + half];
                buf[base + i] = x0 * c0 - x1 * s0;
                buf[base + i + half] = x1 * c1 + x0 * s1;
            }
        }
    }
}

#[inline]
fn bytes_to_f32(bytes: &[u8]) -> &[f32] {
    assert!(
        bytes.len().is_multiple_of(4),
        "bytes_to_f32: len {} not /4",
        bytes.len()
    );
    unsafe { std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4) }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn config_dims() {
        let c = Qwen2VlVitConfig::default();
        assert_eq!(c.head_dim(), 80);
        assert_eq!(c.patch_dim(), 3 * 2 * 14 * 14); // 1176
        assert_eq!(c.merge_unit(), 4);
        assert_eq!(c.hidden_size * c.merge_unit(), 5120); // merger fc1 in-dim
    }

    #[test]
    fn rope_tables_shape() {
        let c = Qwen2VlVitConfig::default();
        // We can't build a ViT without a backend, so test the table builder via
        // a throwaway struct using the same method through a zero backend.
        struct Z;
        impl WeightBackend for Z {
            fn fetch_tensor(&self, n: &str) -> Result<crate::loader::OwnedBytes, String> {
                Err(n.to_string())
            }
            fn has_tensor(&self, _: &str) -> bool {
                false
            }
            fn as_any(&self) -> &dyn std::any::Any {
                self
            }
        }
        let vit = Qwen2VlViT::new(c.clone(), Arc::new(Z));
        let (cos, sin) = vit.build_rope_tables(4, 6, c.head_dim());
        assert_eq!(cos.len(), 4 * 6 * c.head_dim());
        assert_eq!(sin.len(), 4 * 6 * c.head_dim());
        // position (0,0) → all cos=1, sin=0
        for i in 0..c.head_dim() {
            assert!((cos[i] - 1.0).abs() < 1e-6);
            assert!(sin[i].abs() < 1e-6);
        }
    }

    #[test]
    fn window_assignment_tiles() {
        let c = Qwen2VlVitConfig::default();
        struct Z;
        impl WeightBackend for Z {
            fn fetch_tensor(&self, n: &str) -> Result<crate::loader::OwnedBytes, String> {
                Err(n.to_string())
            }
            fn has_tensor(&self, _: &str) -> bool {
                false
            }
            fn as_any(&self) -> &dyn std::any::Any {
                self
            }
        }
        let vit = Qwen2VlViT::new(c, Arc::new(Z));
        // 8 patches per window side; an 8x8 grid → exactly one window.
        let w = vit.assign_windows(8, 8, 8);
        assert!(w.iter().all(|&x| x == 0));
        // 16x16 grid → 4 windows (2x2 tiling)
        let w2 = vit.assign_windows(16, 16, 8);
        assert_eq!(w2.iter().copied().max().unwrap(), 3);
    }
}
